const contactName = $('Format Invitation').item.json.contactName;
const error = $input.first().json;

return [{
  json: {
    success: true,
    message: `⚠️ Meeting scheduled with ${contactName}, but invitation failed to send.\n\n📅 **${meeting.title}**\n🕐 ${meeting.date_time}\n📍 ${meeting.location}\n\n❌ WhatsApp Error: ${error.message || 'Unknown error'}\n\nPlease send the invitation manually.`,
    details: {
      meetingId: meeting.id,
      contactPhone: meeting.contact_phone,
      contactName: meeting.contact_name,
      title: meeting.title,
      dateTime: meeting.date_time,
      purpose: meeting.purpose,
      location: meeting.location,
      status: 'scheduled',
      invitationSent: false,
      error: error.message || 'Failed to send WhatsApp invitation'
    }
  }
}];

const errorData = $input.first().json;

return [{
  json: {
    success: false,
    message: errorData.message,
    details: null
  }
}];

const input = $input.first().json.query || {};

const contactPhoneRaw = (input.contact_phone || '').trim();
const contactPhone = contactPhoneRaw.replace(/\+/g, '');
const contactName = (input.contact_name || '').trim();
const title = (input.title || '').trim();
const dateTime = (input.date_time || '').trim();
const purpose = (input.purpose || '').trim();
const location = (input.location || 'Virtual').trim();

const errors = [];

// Basic validation
if (!contactPhone || contactPhone.length < 10 || isNaN(Number(contactPhone))) {
  errors.push('Valid contact phone number required (must be numeric, min 10 digits)');
}

if (!contactName) {
  errors.push('Contact name is required');
}

if (!title || title.length < 3) {
  errors.push('Meeting title required (min 3 characters)');
}

if (!dateTime) {
  errors.push('Meeting date and time required');
}

if (!purpose || purpose.length < 5) {
  errors.push('Meeting purpose required (min 5 characters)');
}

if (errors.length > 0) {
  return [
    {
      json: {
        error: true,
        success: false,
        message: `❌ Validation failed:\n${errors.join('\n')}`
      }
    }
  ];
}

