// Collect all video binary data from Gemini outputs
// Prepare them for multipart/form-data upload to merge API
const items = $input.all();

if (items.length < 2) {
  throw new Error(`Need at least 2 videos to merge. Found: ${items.length}`);
}

console.log(`Collecting ${items.length} videos for merging...`);

// Collect all binary data from items
const videoBinaries = {};
const videoMetadata = [];

for (let i = 0; i < items.length; i++) {
  const item = items[i];

  // Find binary data (Gemini outputs binary in different formats)
  let binaryData = null;
  let binaryKey = null;

  // Check common binary property names
  if (item.binary) {
    const binaryKeys = Object.keys(item.binary);
    if (binaryKeys.length > 0) {
      binaryKey = binaryKeys[0]; // Use first available binary key
      binaryData = item.binary[binaryKey];
    }
  }

  if (!binaryData) {
    throw new Error(`No binary data found for video ${i + 1}. Available keys: ${Object.keys(item).join(', ')}`);
  }

  // Validate binary data has content
  const size = binaryData.fileSize || binaryData.data?.length || 0;
  if (size === 0) {
    throw new Error(`Video ${i + 1} is empty (0 bytes). Check that Gemini video generation succeeded.`);
  }

  console.log(`Video ${i + 1}: ${size} bytes, MIME: ${binaryData.mimeType || 'video/mp4'}`);

  // Store binary with field name for multipart (file0, file1, file2, etc.)
  // n8n expects binary data in the format it was received
  videoBinaries[`file${i}`] = binaryData;
  videoMetadata.push({
    index: i,
    size: size,
    mimeType: binaryData.mimeType || 'video/mp4',
    fileName: binaryData.fileName || `video_${i}.mp4`
  });
}

console.log(`✓ Collected ${items.length} videos ready for multipart upload`);

// Return single item with all binaries attached
return [{
  json: {
    video_count: items.length,
    message: `Ready to merge ${items.length} videos`,
    videos: videoMetadata
  },
  binary: videoBinaries
}];

