// Loop through all input items
const results = [];

for (const item of $input.all()) {
  try {
    // Parse the media_prompt JSON string
    const mediaPromptObj = JSON.parse(item.json.media_prompt);

    // Essential fields to preserve
    const essentialData = {
      id: item.json.id,
      brand_id: item.json.brand_id,
      post_id: item.json.id,
      calendar_id: item.json.calendar_id
    };

    // Group prompts by scene number
    const sceneMap = new Map();

    Object.entries(mediaPromptObj).forEach(([key, value]) => {
      // Extract scene number
      const sceneMatch = key.match(/scene\s+(\d+)/i);
      const sceneNumber = sceneMatch ? parseInt(sceneMatch[1]) : null;

      if (!sceneMap.has(sceneNumber)) {
        sceneMap.set(sceneNumber, {
          ...essentialData,
          scene_number: sceneNumber
        });
      }

      if (key.toLowerCase().includes('visual prompt')) {
        sceneMap.get(sceneNumber).visual_prompt = value.trim();
      } else if (key.toLowerCase().includes('image to video')) {
        sceneMap.get(sceneNumber).video_prompt = value.trim();
      }
    });

    // Convert map to array and sort by scene number
    Array.from(sceneMap.values())
      .sort((a, b) => a.scene_number - b.scene_number)
      .forEach(scene => results.push(scene));

  } catch (error) {
    results.push({
      error: `Failed to parse media_prompt: ${error.message}`
    });
  }
}

return results;

// Get ALL input items from previous node
const items = $input.all();

const outputs = [];

// Loop through each input item
for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const item = items[itemIndex];

  // Get binary keys from THIS item
  const binaryKeys = Object.keys(item.binary || {});

  if (binaryKeys.length === 0) {
    console.log(`No binary data in item ${itemIndex}, skipping...`);
    continue;
  }

  // Get video prompts from Code in JavaScript2
  const videoPromptRaw = $('Code in JavaScript2').first().json.video_prompt;

  // Convert to array if it's a single string
  let videoPrompts = [];
  if (typeof videoPromptRaw === 'string') {
    videoPrompts = [videoPromptRaw];
  } else if (Array.isArray(videoPromptRaw)) {
    videoPrompts = videoPromptRaw;
  } else {
    videoPrompts = ["Camera slowly zooms in, subject comes to life"];
  }

  if (videoPrompts.length === 0) {
    videoPrompts = ["Camera slowly zooms in, subject comes to life"];
  }

  // Get reference images if available (optional)
  // Expected format: array of base64 encoded images
  let referenceImages = [];
  if ($('Code in JavaScript2').first().json.reference_images) {
    referenceImages = $('Code in JavaScript2').first().json.reference_images;
  }

  // Process each binary key in this item
  for (let binaryIdx = 0; binaryIdx < binaryKeys.length; binaryIdx++) {
    const key = binaryKeys[binaryIdx];
    const binaryData = item.binary[key];
    const base64Image = binaryData.data;

    // Use corresponding prompt for each image (in order)
    const promptIndex = itemIndex % videoPrompts.length;
    const prompt = videoPrompts[promptIndex];

    outputs.push({
      json: {
        prompt: prompt,
        imageBase64: base64Image,
        referenceImages: referenceImages,
        imageIndex: itemIndex,
        totalImages: items.length,
        promptIndex: promptIndex,
        totalPrompts: videoPrompts.length,
        imageKey: key,
        MimeType:$input.first().json.fileName
      }
    });
  }
}

if (outputs.length === 0) {
  throw new Error('No binary images found in any input items');
}

return outputs;

